import { geoAlbersUsa, geoEqualEarth, geoMercator, geoNaturalEarth1, geoPath } from 'https://cdn.jsdelivr.net/npm/d3-geo@3/+esm';
const makers = { albersUsa: geoAlbersUsa, equalEarth: geoEqualEarth, mercator: geoMercator, naturalEarth1: geoNaturalEarth1 };
const pad = data.viewport.padding ?? 8;
const projection = makers[data.projection ?? 'equalEarth']().fitExtent([[pad, pad], [data.viewport.width - pad, data.viewport.height - pad]], data.geojson);
const path = geoPath(projection); const d = path(data.geojson);
